{{
  [
    { label: "STYCZEŃ", value: "1" },
    { label: "LUTY", value: "2" },
    { label: "MARZEC", value: "3" },
    { label: "KWIECIEŃ", value: "4" },
    { label: "MAJ", value: "5" },
    { label: "CZERWIEC", value: "6" },
    { label: "LIPIEC", value: "7" },
    { label: "SIERPIEŃ", value: "8" },
    { label: "WRZESIEŃ", value: "9" },
    { label: "PAŹDZIERNIK", value: "10" },
    { label: "LISTOPAD", value: "11" },
    { label: "GRUDZIEŃ", value: "12" }
  ].filter(m => {
    const wybranyRok = Number(SelectRok.selectedOptionValue);
    const aktualnyRok = new Date().getFullYear();
    const aktualnyMiesiac = new Date().getMonth() + 1;

    if (wybranyRok < aktualnyRok) {
      return true;
    }

    if (wybranyRok === aktualnyRok) {
      return Number(m.value) <= aktualnyMiesiac + 1;
    }

    return false;
  })
}}
